Here's how to test `DataFetcher` with modern MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.NotFound);
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_RespectsTimeout()
    {
        // Pass TestContext.CancellationToken so the [Timeout] is cooperative
        var handler = new FakeHandler("fast", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange — token that is already cancelled
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        var handler = new FakeHandler("data", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_CancelledDuringRequest_ThrowsTaskCanceledException()
    {
        // Arrange — handler that cancels mid-flight
        using var cts = new CancellationTokenSource();
        var handler = new DelayThenCancelHandler(cts);
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // ── Test doubles ──────────────────────────────────────────────

    private sealed class FakeHandler(string content, HttpStatusCode status)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            };
            return Task.FromResult(response);
        }
    }

    private sealed class DelayThenCancelHandler(CancellationTokenSource cts)
        : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            // Simulate work, then cancel
            await Task.Delay(50, CancellationToken.None);
            cts.Cancel();
            cancellationToken.ThrowIfCancellationRequested();
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key takeaways:**

- **Fake `HttpMessageHandler`** — avoids real HTTP calls and lets you control responses
- **`TestContext.CancellationToken`** — pass it to async calls in tests with `[Timeout]` so the timeout is cooperative (MSTest cancels this token when time expires)
- **`Assert.ThrowsExactlyAsync<T>`** — preferred over `[ExpectedException]`; lets you inspect the exception and catches exactly the right type
- **Pre-cancelled token** tests that cancellation is checked *before* the request
- **`DelayThenCancelHandler`** tests that cancellation is respected *during* the request
- **Sealed classes** and **constructor-injected `TestContext`** follow MSTest 3.x+ best practices
